const amqp = require('amqplib');

async function startPaymentConsumer() {
  try {
    const connection = await amqp.connect('amqp://localhost');
    const channel = await connection.createChannel();
    
    const queue = 'payment_events';
    await channel.assertQueue(queue, { durable: true });
    
    channel.prefetch(1);
    
    channel.consume(queue, async (msg) => {
      if (msg !== null) {
        try {
          const paymentData = JSON.parse(msg.content.toString());
          console.log('Processing payment:', paymentData);
          
          // Execute payment logic based on message content
          await processPayment(paymentData);
          
          channel.ack(msg);
        } catch (error) {
          console.error('Error processing payment:', error);
          channel.nack(msg, false, false);
        }
      }
    });
    
    console.log('Payment consumer started and waiting for messages...');
  } catch (error) {
    console.error('Error starting payment consumer:', error);
  }
}

async function processPayment(paymentData) {
  // Payment processing logic based on message content
  switch (paymentData.type) {
    case 'credit_card':
      await processCreditCardPayment(paymentData);
      break;
    case 'paypal':
      await processPaypalPayment(paymentData);
      break;
    case 'bank_transfer':
      await processBankTransfer(paymentData);
      break;
    default:
      throw new Error(`Unknown payment type: ${paymentData.type}`);
  }
}

